#ifndef PAM8403_SPEAKER_H
#define PAM8403_SPEAKER_H
#include <Arduino.h>
void pam_spk_setup();
void pam_spk_write(const int16_t* samples, size_t count);
void pam_spk_tone(uint16_t freq, uint16_t duration_ms);
