firmware_template.source:
#include "pam8403_speaker.h"
#include <driver/i2s.h>
#include <math.h>
#include <string.h>

// S3-PRO default pins — same I2S bus as MAX98357A
#define SPK_BCLK 16
#define SPK_LRC  15
#define SPK_DIN  17
#define SPK_RATE 16000

static float _vol = 1.0f;

void pam_spk_setup() {
    i2s_config_t cfg = {};
    cfg.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX);
    cfg.sample_rate = SPK_RATE;
    cfg.bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT;
    cfg.channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT;
    cfg.communication_format = I2S_COMM_FORMAT_STAND_I2S;
    cfg.dma_buf_count = 8;
    cfg.dma_buf_len = 256;
    cfg.tx_desc_auto_clear = true;
    i2s_driver_install(I2S_NUM_1, &cfg, 0, NULL);
    i2s_pin_config_t pins = { .bck_io_num = SPK_BCLK, .ws_io_num = SPK_LRC, .data_out_num = SPK_DIN, .data_in_num = -1 };
    i2s_set_pin(I2S_NUM_1, &pins);
    i2s_zero_dma_buffer(I2S_NUM_1);
    Serial.println("[pam8403] OK 16kHz stereo");
}

void pam_spk_write(const int16_t* s, size_t n) {
    if (_vol != 1.0f) {
        int16_t buf[256];
        for (size_t i = 0; i < n; i += 256) {
            size_t chunk = (n - i < 256) ? n - i : 256;
            for (size_t j = 0; j < chunk; j++) {
                int32_t v = (int32_t)(s[i+j] * _vol);
                if (v > 32767) v = 32767; if (v < -32768) v = -32768;
                buf[j] = (int16_t)v;
            }
            size_t w = 0;
            i2s_write(I2S_NUM_1, buf, chunk * 2, &w, portMAX_DELAY);
        }
    } else {
        size_t written = 0;
        i2s_write(I2S_NUM_1, s, n * 2, &written, portMAX_DELAY);
    }
}

void pam_spk_tone(uint16_t freq, uint16_t dur) {
    int N = SPK_RATE * dur / 1000;
    int16_t buf[256];
    int fade = SPK_RATE / 100;
    for (int i = 0; i < N; i += 256) {
        int chunk = (N - i < 256) ? N - i : 256;
        for (int j = 0; j < chunk; j++) {
            float a = _vol * 0.7f;
            int idx = i + j;
            if (idx < fade) a *= (float)idx / fade;
            if (idx > N - fade) a *= (float)(N - idx) / fade;
            buf[j] = (int16_t)(sinf(2.0f * 3.14159f * freq * idx / SPK_RATE) * a * 32767.0f);
        }
        pam_spk_write(buf, chunk);
    }
}

void pam_spk_stop() {
    int16_t silence[64] = {0};
    pam_spk_write(silence, 64);
}

void pam_spk_set_volume(int p) { _vol = (float)(p < 0 ? 0 : (p > 200 ? 200 : p)) / 100.0f; }
